queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?component_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:component_id ?cg . ?child a :Components ; p:id ?cg . ?l p:ux_designer_id ?pg . ?parent a :Ux_Designers ; p:id ?pg . } GROUP BY ?child }
  ?child p:component_name ?component_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Ux_Designers } }
  FILTER(?nf = ?total)
}

