ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?description WHERE {
  ?ux_designers_components a :Ux_Designers_Components .
  ?components a :Components .
  ?ux_designers_components p:hasComponents ?components .
  ?ux_designers a :Ux_Designers .
  ?ux_designers_components p:hasUx_Designers ?ux_designers .
  ?ux_designers p:name ?name .
  ?components p:description ?description .
} }
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:component_id ?cg . ?child a :Components ; p:id ?cg . ?l p:ux_designer_id ?pg . ?parent a :Ux_Designers ; p:id ?pg . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Ux_Designers } }
  FILTER(?nf = ?total)
} }
}

